-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        ngx.log(ngx.ERR, "Failed to connect to Redis: ", err)
        return nil, err
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, err = red:auth(REDIS_PASSWORD)
        if not res then
            ngx.log(ngx.ERR, "Failed to authenticate with Redis: ", err)
            return nil, err
        end
    end

    return red
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
    end
end

-- Validate plugin code with basic security checks
local function validate_plugin_code(code, plugin_name)
    if not code or code == "" then
        return false, "Empty plugin code"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size (64KB)"
    end

    -- Blacklist dangerous patterns
    local dangerous_patterns = {
        { pattern = "os%s*%.%s*execute", desc = "os.execute" },
        { pattern = "os%s*%.%s*remove", desc = "os.remove" },
        { pattern = "os%s*%.%s*rename", desc = "os.rename" },
        { pattern = "os%s*%.%s*tmpname", desc = "os.tmpname" },
        { pattern = "io%s*%.", desc = "io module" },
        { pattern = "require%s*%(", desc = "require" },
        { pattern = "require%s*\"", desc = "require" },
        { pattern = "require%s*'", desc = "require" },
        { pattern = "loadfile%s*%(", desc = "loadfile" },
        { pattern = "dofile%s*%(", desc = "dofile" },
        { pattern = "rawset%s*%(", desc = "rawset" },
        { pattern = "rawget%s*%(", desc = "rawget" },
        { pattern = "setmetatable%s*%(", desc = "setmetatable" },
        { pattern = "getmetatable%s*%(", desc = "getmetatable" },
        { pattern = "debug%s*%.", desc = "debug module" },
        { pattern = "package%s*%.", desc = "package module" },
        { pattern = "collectgarbage", desc = "collectgarbage" },
        { pattern = "setfenv", desc = "setfenv" },
        { pattern = "getfenv", desc = "getfenv" },
        { pattern = "coroutine%s*%.", desc = "coroutine module" },
        { pattern = "ngx%s*%.%s*socket", desc = "ngx.socket (use ctx.http instead)" },
        { pattern = "ffi%s*%.", desc = "FFI module" },
    }

    for _, check in ipairs(dangerous_patterns) do
        if string.find(code, check.pattern) then
            return false, string.format(
                "Plugin '%s' contains forbidden pattern: %s",
                plugin_name or "unknown", check.desc
            )
        end
    end

    return true
end

-- Compile plugin code in sandbox
local function compile_plugin(code, plugin_name, request_ctx)
    -- Validate first
    local valid, err = validate_plugin_code(code, plugin_name)
    if not valid then
        return nil, err
    end

    -- Use load() (LuaJIT/Lua 5.1+ compatible)
    local load_func = load or loadstring
    local chunk, compile_err = load_func(code, "=" .. (plugin_name or "plugin"))
    if not chunk then
        return nil, string.format("Compilation error in plugin '%s': %s",
            plugin_name or "unknown", compile_err)
    end

    -- Create sandboxed environment
    local sandbox = create_sandbox_env(request_ctx)

    -- Set the environment for the chunk
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(chunk, sandbox)
    end

    return chunk
end

-- Execute a compiled plugin with timeout protection
local function execute_plugin(chunk, plugin_name)
    local ok, result = pcall(chunk)
    if not ok then
        return nil, string.format("Runtime error in plugin '%s': %s",
            plugin_name or "unknown", tostring(result))
    end

    return result
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    -- Check shared dict cache first
    if plugin_cache then
        local cached_code = plugin_cache:get("code:" .. plugin_name)
        if cached_code then
            ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
            return cached_code
        end
    end

