    if not red then
        return nil, "Redis connection failed: " .. (err or "unknown")
    end

    -- Load plugin code
    local code, err = red:get(REDIS_PLUGIN_PREFIX .. plugin_name)
    if not code or code == ngx.null then
        release_redis_connection(red)
        return nil, string.format("Plugin '%s' not found in Redis", plugin_name)
    end

    -- Load plugin metadata (optional)
    local meta_raw = red:get(REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta")
    local meta = nil
    if meta_raw and meta_raw ~= ngx.null then
        meta = cjson.decode(meta_raw)
    end

    release_redis_connection(red)

    -- Check if plugin is enabled
    if meta and meta.enabled == false then
        return nil, string.format("Plugin '%s' is disabled", plugin_name)
    end

    -- Cache the plugin code
    if plugin_cache then
        local ttl = (meta and meta.cache_ttl) or PLUGIN_CACHE_TTL
        plugin_cache:set("code:" .. plugin_name, code, ttl)
    end

    ngx.log(ngx.INFO, "Plugin '", plugin_name, "' loaded from Redis")
    return code
end

-- Load plugin code from HTTP header
local function load_plugin_from_header()
    local headers = ngx.req.get_headers()

    -- Check for base64-encoded plugin code in header
    local plugin_code_b64 = headers["X-Gateway-Plugin-Code"]
    local plugin_name = headers["X-Gateway-Plugin-Name"] or "header_plugin"

    if not plugin_code_b64 then
        return nil, nil, "No plugin code in headers"
    end

    -- Require an API key for header-based plugin loading
    local api_key = headers["X-Gateway-Admin-Key"]
    local expected_key = os.getenv("GATEWAY_ADMIN_KEY") or ""
    if expected_key == "" then
        return nil, nil, "Header-based plugin loading is not configured (no admin key set)"
    end

    if api_key ~= expected_key then
        return nil, nil, "Invalid admin key for header-based plugin loading"
    end

    -- Decode base64 plugin code
    local code = ngx.decode_base64(plugin_code_b64)
    if not code then
        return nil, nil, "Invalid base64 encoding in X-Gateway-Plugin-Code header"
    end

    return code, plugin_name
end

